	  guided_step_export_desc: { en: "When the manuscript is ready, download EPUB, PDF, or DOCX from the Dashboard.", it: "Quando il manoscritto è pronto, scarica EPUB, PDF o DOCX dalla Dashboard.", es: "Cuando el manuscrito esté listo, descarga EPUB, PDF o DOCX desde el panel.", fr: "Quand le manuscrit est prêt, téléchargez EPUB, PDF ou DOCX depuis le tableau de bord.", de: "Wenn das Manuskript fertig ist, lade EPUB, PDF oder DOCX vom Dashboard herunter." },

