	  dev_no_projects_deleted: { en: "No test projects to delete · Premium intact", it: "Nessun progetto di test da cancellare · Premium intatto", es: "No hay proyectos de prueba que eliminar · Premium intacto", fr: "Aucun projet de test à supprimer · Premium intact", de: "Keine Testprojekte zum Löschen · Premium bleibt intakt" },
