let currentLang: UILanguage = (localStorage.getItem("nexora_ui_lang") as UILanguage) || "en";

export function setUILanguage(lang: UILanguage) {
	  currentLang = lang;
	  localStorage.setItem("nexora_ui_lang", lang);
	  window.dispatchEvent(new Event("scriptora-language-change"));
}

export function getUILanguage(): UILanguage {
  return currentLang;
}

/** Maps UI locale → full language name used in AI diagnostic/report prompts. */
const UI_LANG_TO_SCRIPTORA_LANGUAGE: Record<UILanguage, Language> = {
  en: "English",
  it: "Italian",
  es: "Spanish",
  fr: "French",
  de: "German",
};

/**
 * Scriptora interface language for diagnostics, reports, coaching, and system feedback.
 * Never use book `config.language` for these — book language is for manuscript content only.
 */
export function getScriptoraLanguage(): Language {
  return UI_LANG_TO_SCRIPTORA_LANGUAGE[getUILanguage()] ?? "English";
}

export function t(key: string): string {
	  return translations[key]?.[currentLang] || translations[key]?.["en"] || key;
}

export function tt(key: string, values: Record<string, string | number> = {}): string {
	  return t(key).replace(/\{(\w+)\}/g, (_, name) => String(values[name] ?? ""));
}

export function useUILanguage(): UILanguage {
	  const [lang, setLang] = useState<UILanguage>(() => getUILanguage());

	  useEffect(() => {
	    const sync = () => setLang(getUILanguage());
	    window.addEventListener("scriptora-language-change", sync);
	    window.addEventListener("storage", sync);
	    return () => {
	      window.removeEventListener("scriptora-language-change", sync);
	      window.removeEventListener("storage", sync);
	    };
	  }, []);

	  return lang;
}
